output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?composer ?composerLabel ?lyricist ?lyricistLabel WHERE {
  wd:Q108822278 wdt:P86 ?composer .
  OPTIONAL {
    ?composer rdfs:label ?composerLabel .
    FILTER(lang(?composerLabel) = "en")
  }
  wd:Q108822278 wdt:P676 ?lyricist .
  OPTIONAL {
    ?lyricist rdfs:label ?lyricistLabel .
    FILTER(lang(?lyricistLabel) = "en")
  }
}

